# Modelos Claude que soportan extended thinking (verificado en API)
_CLAUDE_THINKING_MODELS = {
    "claude-opus-4",
    "claude-sonnet-4",
    "claude-3-7-sonnet",
    "claude-3-5-sonnet",
}

def _model_supports_thinking(model: str) -> bool:
    """
    Corrección Bug #3: Verifica si el modelo soporta extended thinking.
    Solo modelos Anthropic Claude específicos lo soportan.
    Qwen3, Llama, DeepSeek, etc. causan error 400 si reciben el parámetro.
    Corrección Bug #7: No usa cache — lee env en cada llamada.
    """
    model_lower = model.lower()

    # Verificar override por variable de entorno (igual que thinking.py)
    for tier_model_env, tier_caps_env in [
        ("ANTHROPIC_DEFAULT_OPUS_MODEL",   "ANTHROPIC_DEFAULT_OPUS_MODEL_SUPPORTED_CAPABILITIES"),
        ("ANTHROPIC_DEFAULT_SONNET_MODEL", "ANTHROPIC_DEFAULT_SONNET_MODEL_SUPPORTED_CAPABILITIES"),
        ("ANTHROPIC_DEFAULT_HAIKU_MODEL",  "ANTHROPIC_DEFAULT_HAIKU_MODEL_SUPPORTED_CAPABILITIES"),
    ]:
        tier_model = os.environ.get(tier_model_env, "").lower()
        tier_caps  = os.environ.get(tier_caps_env, "")
        if tier_model and tier_caps and model_lower == tier_model:
            return "thinking" in {c.strip().lower() for c in tier_caps.split(",")}

    # Modelos de terceros conocidos sin thinking
    for prefix in ("qwen", "deepseek", "llama", "mistral", "gemma", "phi", "grok"):
        if prefix in model_lower:
            logger.debug(f"Thinking desactivado para '{model}' (modelo de tercero)")
            return False

    # Lista conocida de modelos Claude con thinking
    return any(name in model_lower for name in _CLAUDE_THINKING_MODELS)


def _safe_thinking_budget(raw) -> int:
    """
    Corrección Bug #9: Valida budget_tokens (evita NaN del parseInt original).
    """
    try:
        val = int(raw)
        if val <= 0:
            logger.warning(f"thinking_budget inválido ({raw!r}), usando 10000")
            return 10000
        return min(val, 100_000)
    except (ValueError, TypeError):
        logger.warning(f"thinking_budget no es número ({raw!r}), usando 10000")
        return 10000


