{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, Footer, Header, TabStopType, TabStopPosition,
  PageBreak
} = require('docx');
const fs = require('fs');

// ── Colores ──────────────────────────────────────────────────────────────
const AZUL      = "1F4E79";
const AZUL_MED  = "2E75B6";
const AZUL_CLAR = "D6E4F0";
const VERDE     = "1D6A38";
const VERDE_CL  = "D6F0E0";
const GRIS      = "595959";
const GRIS_CL   = "F2F2F2";
const NARANJA   = "C55A11";
const NARANJA_CL= "FCE4D6";
const BLANCO    = "FFFFFF";

// ── Helpers ───────────────────────────────────────────────────────────────
const border  = (color="CCCCCC") => ({ style: BorderStyle.SINGLE, size: 1, color });
const borders = (color="CCCCCC") => ({ top: border(color), bottom: border(color), left: border(color), right: border(color) });

function titulo(text) {
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 0, after: 120 },
    children: [new TextRun({ text, bold: true, size: 52, color: BLANCO, font: "Arial" })],
    shading: { fill: AZUL, type: ShadingType.CLEAR },
  });
}

function subtituloCentro(text, color=BLANCO, bg=AZUL_MED) {
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 0, after: 200 },
    shading: { fill: bg, type: ShadingType.CLEAR },
    children: [new TextRun({ text, size: 24, color, font: "Arial" })],
  });
}

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 160 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: AZUL_MED, space: 4 } },
    children: [new TextRun({ text, bold: true, size: 32, color: AZUL, font: "Arial" })],
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 120 },
    children: [new TextRun({ text, bold: true, size: 26, color: AZUL_MED, font: "Arial" })],
  });
}

function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 200, after: 80 },
    children: [new TextRun({ text, bold: true, size: 22, color: GRIS, font: "Arial" })],
  });
}

function p(runs) {
  if (typeof runs === 'string') runs = [{ text: runs }];
  return new Paragraph({
    spacing: { before: 60, after: 100 },
    children: runs.map(r => new TextRun({ font: "Arial", size: 20, color: "333333", ...r })),
  });
}

function bullet(text, nivel=0) {
  return new Paragraph({
    numbering: { reference: "bullets", level: nivel },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, font: "Arial", size: 20, color: "333333" })],
  });
}

function code(text) {
  return new Paragraph({
    spacing: { before: 80, after: 80 },
    indent: { left: 720 },
    shading: { fill: "1E1E1E", type: ShadingType.CLEAR },
    children: [new TextRun({ text, font: "Courier New", size: 18, color: "D4D4D4" })],
  });
}

function espacio(n=1) {
  return Array(n).fill(null).map(() => new Paragraph({ children: [new TextRun("")], spacing: { before: 0, after: 60 } }));
}

function badgeRow(items) {
  // Fila de badges de estado
  return new Paragraph({
    alignment: AlignmentType.CENTER,
    spacing: { before: 120, after: 120 },
    children: items.flatMap((item, i) => [
      new TextRun({ text: ` ${item.icon} ${item.text} `, bold: true, size: 18,
        color: item.ok ? VERDE : NARANJA, font: "Arial",
        shading: { fill: item.ok ? VERDE_CL : NARANJA_CL } }),
      new TextRun({ text: "   ", font: "Arial", size: 18 }),
    ]),
  });
}

// ── Tabla de estado ───────────────────────────────────────────────────────
function tablaEstado(filas) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [3200, 2080, 4080],
    rows: [
      new TableRow({
        tableHeader: true,
        children: ["Componente", "Estado", "Detalle"].map(h =>
          new TableCell({
            borders: borders(AZUL_MED),
            shading: { fill: AZUL_MED, type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 150, right: 150 },
            width: { size: h === "Componente" ? 3200 : h === "Estado" ? 2080 : 4080, type: WidthType.DXA },
            children: [new Paragraph({ alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: h, bold: true, color: BLANCO, font: "Arial", size: 20 })] })],
          })
        ),
      }),
      ...filas.map((fila, idx) => new TableRow({
        children: fila.map((celda, ci) =>
          new TableCell({
            borders: borders("DDDDDD"),
            shading: { fill: idx % 2 === 0 ? BLANCO : GRIS_CL, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 150, right: 150 },
            width: { size: ci === 0 ? 3200 : ci === 1 ? 2080 : 4080, type: WidthType.DXA },
            children: [new Paragraph({
              alignment: ci === 1 ? AlignmentType.CENTER : AlignmentType.LEFT,
              children: [new TextRun({
                text: celda,
                font: "Arial", size: 18,
                color: celda.includes("✅") ? VERDE : celda.includes("⬜") ? NARANJA : "333333",
                bold: celda.includes("✅") || celda.includes("⬜"),
              })],
            })],
          })
        ),
      })),
    ],
  });
}

// ── Tabla de bugs ─────────────────────────────────────────────────────────
function tablaBugs(filas) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [960, 2400, 6000],
    rows: [
      new TableRow({
        tableHeader: true,
        children: ["Bug", "Archivo", "Descripción"].map((h, ci) =>
          new TableCell({
            borders: borders(AZUL_MED),
            shading: { fill: AZUL_MED, type: ShadingType.CLEAR },
            margins: { top: 100, bottom: 100, left: 150, right: 150 },
            width: { size: ci === 0 ? 960 : ci === 1 ? 2400 : 6000, type: WidthType.DXA },
            children: [new Paragraph({ alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: h, bold: true, color: BLANCO, font: "Arial", size: 20 })] })],
          })
        ),
      }),
      ...filas.map((fila, idx) => new TableRow({
        children: fila.map((celda, ci) =>
          new TableCell({
            borders: borders("DDDDDD"),
            shading: { fill: idx % 2 === 0 ? BLANCO : GRIS_CL, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 150, right: 150 },
            width: { size: ci === 0 ? 960 : ci === 1 ? 2400 : 6000, type: WidthType.DXA },
            children: [new Paragraph({
              alignment: ci === 0 ? AlignmentType.CENTER : AlignmentType.LEFT,
