// ── Rutas del PC de Santiago (NO cambiar) ────────────────────────────────
const PYTHON = 'C:\\Users\\Admin\\AppData\\Local\\Python\\bin\\python.exe';
const CLAW   = 'C:\\Users\\Admin\\Downloads\\claw_completo (2)\\claw_completo\\clawspring.py';
const MODEL  = 'ollama/qwen2.5:1.5b';

// ── Configuracion ────────────────────────────────────────────────────────
const TIMEOUT_MS    = 120000;   // 2 min max por respuesta (qwen2.5 es rapido)
const MAX_MSG_LEN   = 3800;     // WhatsApp corta cerca de 4096 chars
const PREFIJO_BOT   = '[Claw]'; // Prefijo en respuestas (ayuda a distinguir)

// ── Cola de mensajes (evita colapso si llegan varios a la vez) ───────────
let procesando = false;
const cola = [];

// ── Cliente WhatsApp ─────────────────────────────────────────────────────
const client = new Client({
    authStrategy: new LocalAuth({ dataPath: path.join(os.homedir(), '.claw', 'whatsapp') }),
    puppeteer: {
        headless: true,
        args: [
            '--no-sandbox',
            '--disable-setuid-sandbox',
            '--disable-dev-shm-usage',
            '--disable-gpu',          // sin GPU en el PC de Santiago
        ],
    },
});

// ── Eventos del cliente ──────────────────────────────────────────────────

client.on('qr', (qr) => {
    console.log('\n=== Escanea este QR con WhatsApp de tu celular ===\n');
    qrcode.generate(qr, { small: true });
    console.log('\nAbre WhatsApp -> Dispositivos vinculados -> Vincular un dispositivo\n');
});

client.on('ready', () => {
    const hora = new Date().toLocaleTimeString('es-CO');
    console.log(`[${hora}] Claw WhatsApp Bridge listo`);
    console.log(`Modelo: ${MODEL}`);
    console.log('Escribe desde tu celular para hablar con Claw.\n');
});

client.on('auth_failure', (msg) => {
    console.error('Error de autenticacion:', msg);
    console.error('Borra la carpeta ~/.claw/whatsapp y vuelve a escanear el QR.');
});

client.on('disconnected', (reason) => {
    console.log('Desconectado:', reason);
    console.log('Reinicia bridge.js para reconectar.');
});

// ── Recepcion de mensajes ────────────────────────────────────────────────

client.on('message', async (msg) => {
    // Ignorar mensajes de grupos, estados y del propio bot
    if (msg.isGroupMsg || msg.isStatus || msg.fromMe) return;

    // Ignorar mensajes vacios o no de texto
    const texto = (msg.body || '').trim();
    if (!texto) return;

    // Agregar a la cola
    cola.push({ msg, texto });
    procesarCola();
});

// ── Procesador de cola ───────────────────────────────────────────────────

async function procesarCola() {
    if (procesando || cola.length === 0) return;
    procesando = true;

    const { msg, texto } = cola.shift();
    const hora = new Date().toLocaleTimeString('es-CO');
    console.log(`[${hora}] Mensaje recibido: ${texto.slice(0, 80)}`);

    try {
        // Indicador de "escribiendo..." en WhatsApp
        const chat = await msg.getChat();
        await chat.sendStateTyping();

        // Llamar a Claw
        const respuesta = await llamarClaw(texto);

        // Detener indicador
        await chat.clearState();

        // Enviar respuesta (en partes si es muy larga)
        const partes = dividirMensaje(respuesta, MAX_MSG_LEN);
        for (const parte of partes) {
            await msg.reply(parte);
        }

        console.log(`[${hora}] Respuesta enviada (${respuesta.length} chars)`);

    } catch (err) {
        console.error(`[${hora}] Error:`, err.message);
        try {
            await msg.reply(
                `${PREFIJO_BOT} Error al procesar tu mensaje.\n` +
                `Detalle: ${err.message.slice(0, 200)}\n` +
                `Verifica que Ollama este corriendo: ollama ps`
            );
        } catch (_) { /* si falla el reply, ignorar */ }
    }

    procesando = false;
    // Procesar siguiente si hay en cola
    if (cola.length > 0) procesarCola();
}

// ── Llamada a Claw ───────────────────────────────────────────────────────

function llamarClaw(prompt) {
    return new Promise((resolve, reject) => {
        // Timeout de seguridad
        const timer = setTimeout(() => {
            reject(new Error(`Timeout: Claw tardo mas de ${TIMEOUT_MS/1000} segundos.`));
        }, TIMEOUT_MS);

        try {
            // execFileSync evita inyeccion de shell - mas seguro que execSync
            const resultado = execFileSync(
                PYTHON,
                [
                    CLAW,
                    '--print',              // modo no interactivo
                    '--model', MODEL,
                    '--accept-all',         // sin confirmaciones manuales
                    prompt,                 // el mensaje del usuario
                ],
                {
                    encoding: 'utf8',
                    timeout:  TIMEOUT_MS,
                    maxBuffer: 1024 * 1024 * 10,  // 10 MB max output
                    env: {
                        ...process.env,
                        ANTHROPIC_API_KEY: 'ollama',
                        PYTHONIOENCODING:  'utf-8',
                    },
                }
            );

            clearTimeout(timer);
            const texto = resultado.trim();
            resolve(texto || '(Claw respondio con texto vacio)');

        } catch (err) {
            clearTimeout(timer);
            // execFileSync lanza si el proceso sale con codigo != 0
            const salida = (err.stdout || '') + (err.stderr || '');
            reject(new Error(salida.slice(0, 500) || err.message));
        }
    });
}

// ── Utilidades ───────────────────────────────────────────────────────────

function dividirMensaje(texto, maxLen) {
    if (texto.length <= maxLen) return [texto];

    const partes = [];
    let restante = texto;
    while (restante.length > 0) {
        // Cortar en el ultimo salto de linea antes del limite
        let corte = maxLen;
        if (restante.length > maxLen) {
            const ultimoSalto = restante.lastIndexOf('\n', maxLen);
            corte = ultimoSalto > maxLen * 0.5 ? ultimoSalto : maxLen;
        }
        partes.push(restante.slice(0, corte).trim());
        restante = restante.slice(corte).trim();
    }
    return partes;
}

// ── Arranque ─────────────────────────────────────────────────────────────

console.log('Iniciando Claw WhatsApp Bridge...');
console.log(`Python: ${PYTHON}`);
console.log(`Claw:   ${CLAW}`);
console.log(`Modelo: ${MODEL}\n`);

client.initialize();

// Capturar Ctrl+C limpiamente
process.on('SIGINT', async () => {
    console.log('\nCerrando bridge...');
    await client.destroy();
    process.exit(0);
});

